    FILTER(isLiteral(?value))
  } UNION {
    BIND("4. 추천" AS ?section)
    hrd:PERSON_01 hrd:receivesRecommendation ?rec .
    ?rec ?predProp ?value .
    BIND(REPLACE(STR(?predProp), ".*#", "") AS ?predicate)
    FILTER(isLiteral(?value))
  } UNION {
    BIND("5. 성과" AS ?section)
